INSERT INTO "Reference" ("id", "title", "description", "content", "category", "createdAt", "updatedAt") VALUES (md5(random()::text), 'ГОСТ 19917-2014', 'Общие технические условия для мебельной продукции', '{"_type": "text", "sections": [{"title": "ГОСТ 19917-2014. Мебельные изделия. Общие технические условия", "text": "Настоящий стандарт распространяется на мебельные изделия (далее — мебель), предназначенные для общественных и жилых помещений, и устанавливает общие технические условия, требования безопасности, требования к надёжности, эксплуатации, хранения и транспортирования."}, {"title": "1. Общие положения", "text": "1.1. Мебельные изделия подразделяются на виды: мягкая мебель, корпусная мебель, столярно-плиточная мебель, мебель из натуральной древесины, комбинированная мебель.\n\n1.2. Мебель классифицируется по назначению: для жилых помещений (кухонная, спальная, гостиная, прихожая), для общественных помещений (офисная, для учреждений, для торговли), для специальных помещений (медицинская, для библиотек, архивов)."}, {"title": "2. Требования к материалам", "text": "2.1. Для изготовления мебели应当 применяться материалы, соответствующие требованиям нормативных документов.\n\n2.2. Древесина应当 иметь влажность не более 12% для корпусной мебели и не более 8% для столярных изделий.\n\n2.3. Конструкционные материалы应当 обеспечивать необходимую прочность и жёсткость.\n\n2.4. Отделочные материалы应当 обеспечивать заданный внешний вид и защиту от окружающей среды.\n\n2.5. Крепёжные изделия应当 быть изготовлены из коррозионностойких материалов."}, {"title": "3. Требования к конструкции", "text": "3.1. Конструкция应当 обеспечивать: устойчивость и упругость, удобство пользования, технологичность изготовления, ремонтопригодность.\n\n3.2. Размеры应当 соответствовать требованиям эргономики.\n\n3.3. Допускаемые отклонения от номинальных размеров: ±2 мм для корпусной мебели, ±3-5 мм для мягкой мебели.\n\n3.4. Предельные отклонения от прямолинейности: не более 2 мм на 1000 мм длины.\n\n3.5. Зазоры between подвижными элементами: 1-3 мм.\n\n3.6. Перекосы фасадов: не более 2 мм по диагонали."}, {"title": "4. Требования к отделке", "text": "4.1. Отделочные покрытия应当 обеспечивать: защиту материала, заданный внешний вид, удобство ухода.\n\n4.2. Качество отделки: равномерность окраски, отсутствие потёков, пузырей, царапин.\n\n4.3. Ламинированные покрытия: равномерная окраска, отсутствие расслоений, прочность сцепления не менее 0,4 МПа.\n\n4.4. Шпонированные поверхности: равномерный рисунок, отсутствие складок, прочность сцепления не менее 0,8 МПа."}, {"title": "5. Требования безопасности", "text": "5.1. Мебель应当 не представлять опасность для потребителя.\n\n5.2. Конструкция应当 исключать: травмирование, наличие острых углов и кромок, защемление пальцев.\n\n5.3. Уровень выбросов формальдегида应当 не превышать 0,124 мг/м³ для корпусной мебели.\n\n5.4. Мебель应当 соответствовать требованиям пожарной безопасности по ГОСТ 30244."}, {"title": "6. Надёжность и срок службы", "text": "6.1. Гарантийный срок эксплуатации: не менее 18 месяцев для ДСП/МДФ, 24 месяца для натуральной древесины, 36 месяцев для мягкой мебели.\n\n6.2. Нормативный срок службы: не менее 5 лет для корпусной мебели, 3 года для мягкой мебели, 10 лет для мебели из натуральной древесины.\n\n6.3. Условия эксплуатации: температура +10°С до +35°С, влажность 30-80%.\n\n6.4. Нагрузки: полки до 100 кг, столы до 150 кг, кровати до 200 кг.\n\n6.5. Циклы: петли — 20 000, направляющие — 50 000, раздвижные системы — 10 000."}, {"title": "7. Маркировка и упаковка", "text": "7.1. Маркировка应当 содержать: наименование предприятия, товарный знак, наименование изделия, дату изготовления, обозначение стандарта.\n\n7.2. Упаковка应当 обеспечивать сохранность при транспортировании и хранении.\n\n7.3. Сопроводительная документация: инструкция по эксплуатации, гарантийный талон, перечень комплектующих."}]}', 'ГОСТ', NOW(), NOW());
INSERT INTO "Reference" ("id", "title", "description", "content", "category", "createdAt", "updatedAt") VALUES (md5(random()::text), 'ГОСТ 20400-2017', 'Общие технические условия для мебельной продукции', '{"_type": "text", "sections": [{"title": "ГОСТ 20400-2017. Продукция мебельного производства. Общие технические условия", "text": "Настоящий стандарт распространяется на продукцию мебельного производства и устанавливает общие технические условия, требования к безопасности, надёжности, долговечности, технологичности и эстетичности."}, {"title": "1. Общие требования", "text": "1.1. Виды мебельной продукции: корпусная мебель, мягкая мебель, кухонная мебель, спальная мебель, офисная мебель, торговая мебель, мебель для учреждений.\n\n1.2. Классификация по назначению: для жилых, общественных, производственных и специальных помещений."}, {"title": "2. Требования к материалам", "text": "2.1. Древесные плиты应当 соответствовать ГОСТ 10632 (ДСП), ГОСТ 20022 (ДВП), ГОСТ 33004 (МДФ).\n\n2.2. Ламинированные ДСП应当 иметь класс эмиссии Е1 или выше.\n\n2.3. Натуральная древесина应当 иметь влажность не более 12%.\n\n2.4. Фурнитура应当 соответствовать ГОСТ 27003 (петли), ГОСТ 23747 (направляющие), ГОСТ 23748 (ручки)."}, {"title": "3. Требования к конструкции", "text": "3.1. Конструкция应当 обеспечивать: функциональное назначение, прочность и устойчивость, удобство эксплуатации, ремонтопригодность, безопасность.\n\n3.2. Допуски на размеры: ±1,5 мм для корпусной мебели.\n\n3.3. Предельные отклонения от прямоугольности: не более 2 мм на 1000 мм.\n\n3.4. Зазоры: 1-2 мм между подвижными элементами."}, {"title": "4. Требования к отделке", "text": "4.1. Лакокрасочные покрытия: равномерность окраски, отсутствие потёков, прочность не менее 3 Н на отрыв.\n\n4.2. Ламинированные покрытия: прочность сцепления не менее 0,4 МПа.\n\n4.3. Плён ПВХ покрытия: прочность сцепления не менее 0,3 МПа.\n\n4.4. Кромочные материалы应当 обеспечивать защиту торцов и эстетичный外观."}, {"title": "5. Требования безопасности", "text": "5.1. Мебельная продукция应当 соответствовать ТР ТС 025/2012.\n\n5.2. Конструкция应当 исключать: острые углы, травмирование, защём пальцев.\n\n5.3. Устойчивость应当 обеспечиваться при наклоне на 10°.\n\n5.4. Выделение веществ: формальдегид — не более 0,124 мг/м³, фенол — не более 0,003 мг/м³."}, {"title": "6. Надёжность и долговечность", "text": "6.1. Гарантийный срок: не менее 12 месяцев для корпусной мебели, 18 месяцев для мягкой мебели, 24 месяца для натуральной древесины.\n\n6.2. Нормативный срок службы: 5 лет для корпусной, 3 года для мягкой, 10 лет для натуральной.\n\n6.3. Условия эксплуатации: температура +5°С до +35°С, влажность 30-80%."}, {"title": "7. Маркировка и упаковка", "text": "7.1. Маркировка应当 содержать: наименование предприятия, товарный знак,型号 изделия, дату изготовления.\n\n7.2. Упаковка应当 обеспечивать сохранность при транспортировании.\n\n7.3. Документация: паспорт изделия, инструкция по эксплуатации, гарантийный талон."}]}', 'ГОСТ', NOW(), NOW());